// Parse Claude's JSON reply, render the HTML email body matching the SampleIssuePreview UI.
const reply = $input.first().json;
const raw = reply?.content?.[0]?.text || '{}';

let parsed;
try {
  // Strip optional fences just in case
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude returned non-JSON: ' + raw.slice(0, 500));
}

const stories = Array.isArray(parsed.stories) ? parsed.stories.slice(0, 5) : [];
if (stories.length === 0) throw new Error('Claude returned zero stories');

const issueData = $('Combine + Tag Issue').first().json;
const issueNumber = issueData.issue_number;
const dateLabel = new Date(issueData.date_iso).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

const storiesHtml = stories.map((s, i) => `
  <tr><td style="padding:0 0 28px 0;">
    <div style="font-family:'JetBrains Mono',ui-monospace,monospace;font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#00a6ff;margin-bottom:8px;">${String(i+1).padStart(2,'0')}</div>
    <h3 style="margin:0 0 8px 0;font-family:Inter,Arial,sans-serif;font-size:18px;line-height:1.3;color:#e8f0fe;font-weight:600;"><a href="${s.url}" style="color:#e8f0fe;text-decoration:none;">${s.headline}</a></h3>
    <p style="margin:0 0 8px 0;font-family:Inter,Arial,sans-serif;font-size:15px;line-height:1.55;color:#8da2c0;">${s.take}</p>
    <div style="font-family:'JetBrains Mono',ui-monospace,monospace;font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#8da2c0;"><a href="${s.url}" style="color:#8da2c0;text-decoration:underline;">${s.source}</a></div>
  </td></tr>
`).join('');

const html = `<!doctype html>
<html><head><meta charset="utf-8"></head>
<body style="margin:0;padding:0;background:#0a1628;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#0a1628;">
<tr><td align="center" style="padding:32px 16px;">
  <table role="presentation" width="560" cellpadding="0" cellspacing="0" style="max-width:560px;width:100%;background:#0f1a2e;border:1px solid rgba(141,162,192,0.2);border-radius:8px;padding:28px;">
    <tr><td style="border-bottom:1px solid rgba(141,162,192,0.2);padding-bottom:16px;">
      <table role="presentation" width="100%"><tr>
        <td style="font-family:'JetBrains Mono',ui-monospace,monospace;font-size:11px;letter-spacing:0.22em;text-transform:uppercase;color:#00a6ff;">AI NEWS · #${String(issueNumber).padStart(3,'0')}</td>
        <td align="right" style="font-family:'JetBrains Mono',ui-monospace,monospace;font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#8da2c0;">${dateLabel} · 7h</td>
      </tr></table>
    </td></tr>
    <tr><td style="padding:24px 0 0 0;"><table role="presentation" width="100%">${storiesHtml}</table></td></tr>
    <tr><td style="border-top:1px solid rgba(141,162,192,0.2);padding-top:16px;text-align:center;font-family:Inter,Arial,sans-serif;font-size:12px;color:#8da2c0;">
      <p style="margin:0 0 6px 0;">— Manu · <a href="https://instagram.com/manu_ai.to" style="color:#00a6ff;text-decoration:none;">@manu_ai.to</a></p>
      <p style="margin:0;font-size:11px;"><a href="https://taiyka.com/brief/unsubscribe?email={{EMAIL}}" style="color:#8da2c0;text-decoration:underline;">Se désinscrire en 1 clic</a></p>
    </td></tr>
  </table>
</td></tr></table>
</body></html>`;

return [{
  json: {
    issue_number: issueNumber,
    date_iso: issueData.date_iso,
    stories,
    stories_json: JSON.stringify(stories),
    html_body: html,
    subject: `[DRAFT] AI NEWS #${String(issueNumber).padStart(3,'0')} — ${dateLabel}`,
    status: 'draft',
  },
}];
